<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Cache;
use Illuminate\Support\Facades\Validator;

class WebsitePreviewController extends Controller
{
    public function show(Request $request)
    {
        $validator = Validator::make($request->all(), [
            'url' => ['required', 'string', 'max:2048'],
        ]);

        if ($validator->fails()) {
            return response()->json([
                'message' => 'Invalid URL provided.',
                'errors' => $validator->errors(),
            ], 422);
        }

        $url = trim($request->input('url'));

        if (!filter_var($url, FILTER_VALIDATE_URL)) {
            return response()->json([
                'message' => 'Invalid URL provided.',
            ], 422);
        }

        $cacheKey = 'website_preview:' . sha1($url);

        $preview = Cache::remember($cacheKey, now()->addMinutes(10), function () use ($url) {
            return $this->fetchPreview($url);
        });

        if (!$preview['success']) {
            return response()->json([
                'message' => $preview['message'],
            ], 422);
        }

        return response()->json([
            'url' => $url,
            'title' => $preview['title'],
            'description' => $preview['description'],
            'image' => $preview['image'],
            'site_name' => $preview['site_name'],
            'favicon' => $preview['favicon'],
        ]);
    }

    protected function fetchPreview(string $url): array
    {
        $ch = curl_init();

        curl_setopt_array($ch, [
            CURLOPT_URL => $url,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_FOLLOWLOCATION => true,
            CURLOPT_MAXREDIRS => 5,
            CURLOPT_CONNECTTIMEOUT => 10,
            CURLOPT_TIMEOUT => 20,
            CURLOPT_USERAGENT => 'Mozilla/5.0 (compatible; LinkPreviewBot/1.0)',
            CURLOPT_SSL_VERIFYPEER => true,
            CURLOPT_SSL_VERIFYHOST => 2,
            CURLOPT_HEADER => false,
        ]);

        $html = curl_exec($ch);
        $curlError = curl_error($ch);
        $httpCode = (int) curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);

        if ($html === false || $curlError) {
            return [
                'success' => false,
                'message' => 'Unable to fetch the provided URL.',
            ];
        }

        if ($httpCode < 200 || $httpCode >= 400) {
            return [
                'success' => false,
                'message' => 'The provided URL returned an invalid response.',
            ];
        }

        $title = null;
        $description = null;
        $image = null;
        $siteName = null;
        $favicon = null;

        libxml_use_internal_errors(true);

        $dom = new \DOMDocument();
        $dom->loadHTML($html);

        $xpath = new \DOMXPath($dom);

        $titleNode = $xpath->query('//meta[@property="og:title"]/@content')->item(0)
            ?: $xpath->query('//title')->item(0);

        if ($titleNode) {
            $title = trim($titleNode->nodeValue);
        }

        $descriptionNode = $xpath->query('//meta[@property="og:description"]/@content')->item(0)
            ?: $xpath->query('//meta[@name="description"]/@content')->item(0);

        if ($descriptionNode) {
            $description = trim($descriptionNode->nodeValue);
        }

        $imageNode = $xpath->query('//meta[@property="og:image"]/@content')->item(0);
        if ($imageNode) {
            $image = trim($imageNode->nodeValue);
        }

        $siteNameNode = $xpath->query('//meta[@property="og:site_name"]/@content')->item(0);
        if ($siteNameNode) {
            $siteName = trim($siteNameNode->nodeValue);
        }

        $faviconNode = $xpath->query('//link[contains(@rel,"icon")]/@href')->item(0);
        if ($faviconNode) {
            $favicon = trim($faviconNode->nodeValue);
        }

        $baseUrl = $this->getBaseUrl($url);

        if ($image && $this->isRelativeUrl($image)) {
            $image = $this->resolveUrl($baseUrl, $image);
        }

        if ($favicon && $this->isRelativeUrl($favicon)) {
            $favicon = $this->resolveUrl($baseUrl, $favicon);
        }

        return [
            'success' => true,
            'title' => $title,
            'description' => $description,
            'image' => $image,
            'site_name' => $siteName,
            'favicon' => $favicon,
        ];
    }

    protected function getBaseUrl(string $url): string
    {
        $parts = parse_url($url);

        if (!$parts || empty($parts['scheme']) || empty($parts['host'])) {
            return $url;
        }

        $base = $parts['scheme'] . '://' . $parts['host'];

        if (!empty($parts['port'])) {
            $base .= ':' . $parts['port'];
        }

        return $base;
    }

    protected function isRelativeUrl(string $url): bool
    {
        return !preg_match('/^https?:\/\//i', $url) && !str_starts_with($url, '//');
    }

    protected function resolveUrl(string $baseUrl, string $relativeUrl): string
    {
        if (str_starts_with($relativeUrl, '//')) {
            $scheme = parse_url($baseUrl, PHP_URL_SCHEME) ?: 'https';
            return $scheme . ':' . $relativeUrl;
        }

        if (str_starts_with($relativeUrl, '/')) {
            return rtrim($baseUrl, '/') . $relativeUrl;
        }

        return rtrim($baseUrl, '/') . '/' . ltrim($relativeUrl, '/');
    }
}